var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......결국 그렇게 꼬맹이까지 데리고 들어갔지.","JPN":"……結局、そうしてガキまで連れていくことになったんだ。","ENG":"... And so I ended up dragging the kid in there too.","TWN":"……最後還是把那個小鬼帶去了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"내 평생 그렇게 말 안 듣는 애는 처음이었어.","JPN":"あそこまで言うことを聞かない子どもは初めてだった。","ENG":"I never met anyone who did the complete opposite of what I said for everything.","TWN":"我這輩子第一次遇到這麼不聽話的孩子。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이야기를 들어 보니 그 대시라는 아이를 제법 아꼈나 보군.","JPN":"そのダッシュという子をずいぶん可愛がっていたようだな。","ENG":"Sounds like you cared very much about this Dash girl.","TWN":"看起來，你好像很疼愛那個叫黛西的孩子。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"벌써 취했나? 나한테 그 꼬맹이는 그냥 관리하기 귀찮은 담보물이야.","JPN":"もう酔ってきたのか？　私にとってあのガキはただの面倒な担保にすぎない。","ENG":"Are you drunk already? That kid was just a nuisance to me. Collateral.","TWN":"你是醉了嗎？對我來說，那個小鬼不過是個麻煩的抵押品。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"글쎄. 내 생각엔 그저 당신이 솔직하지 못한 것 같은데.","JPN":"どうかな。個人的には、君が素直じゃないだけに見えるんだが。","ENG":"I don't know. It sounds like you're not being very honest with yourself.","TWN":"是嗎，我覺得你好像不太誠實。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"호라이즌과 똑같은 소릴 하는군.","JPN":"ホライズンと同じことを言うな。","ENG":"You sound just like Horizon.","TWN":"地平線也是這麼說的。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그 녀석도 하자투성이 인공지능 주제에 툭 하면 사람 심리를 분석하겠다고 달려들었지.","JPN":"あいつも問題だらけの人工知能のくせに、しょっちゅう人の心理を分析するとか言ってうるさかったな。","ENG":"That fool always tried to play shrink with me, when she's nothing but a buggy A.I.","TWN":"那傢伙明明是個充滿瑕疵的人工智慧，卻動不動就分析人類的心理。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 정말 그렇게 싫으면 어째서 대시 양을 <color=#ffd34c>담보</color>로 받아 온 건가?","JPN":"しかし、本気で面倒ならどうしてダッシュという子を<color=#ffd34c>担保</color>として引き取ったんだ？","ENG":"If you found her so annoying, why did you accept Dash as <color=#ffd34c>collateral</color>?","TWN":"不過，如果你真的那麼討厭她，為什麼還要接受黛西作為<color=#ffd34c>抵押品</color>呢？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그 녀석 부모들 때문에. 돈이 생기는 대로 도박에 탕진하는 쓰레기들이었거든.","JPN":"あいつの親のせいだ。あれは金が入り次第、賭博に使い果たすゴミみたいな人間だった。","ENG":"Because of her parents. They were a couple of scumbags who always gambled away their money.","TWN":"因為她的父母。她的父母是只要一有錢就去賭桌上揮霍的人渣。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"돈을 못 갚겠으면 담보라도 내놓으라고 하니까 그 꼬맹이를 덥석 떠맡긴 거야.","JPN":"金を返せないなら担保を取ると言ったら、あのガキを押し付けられたんだ。","ENG":"When I told them to put up collateral if they couldn't pay, they just handed me their daughter.","TWN":"當時我說如果沒錢就交出抵押品，他們就把那個小鬼推給了我。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......카운터인 아이를 말이지.","JPN":"……カウンターの子どもをな。","ENG":"A Counter, no less.","TWN":"……就是那個制裁者孩子吧。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"카운터니까 받았지. 돈벌이가 될 줄 알았으니까.","JPN":"カウンターだから引き受けたわけさ。金になると思ったから。","ENG":"That's exactly why I took her. I thought she could earn a pretty penny.","TWN":"因為是制裁者，所以才接受的。本以為她能賺錢呢。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"뭐, 그렇다고 쳐도......","JPN":"まあ、それにしても……","ENG":"Even so...","TWN":"就算如此……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이야기를 듣는 내내 그 아이가 다치지 않도록 애쓰는 모습이 눈에 선하던데.","JPN":"話を聞いている間、ずっとその子が怪我をしないように努力する君の姿が目に浮かんだよ。","ENG":"From what I could gather, you were always trying to protect her.","TWN":"聽你說的過程中，我能感覺到你努力保護那個孩子不受傷害。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"사채업에 대해선 문외한인가 보군. 담보물이 상하면 나중에 제값을 못 받아.","JPN":"この業界については門外漢のようだな。担保に傷でもついたら後で元の値段で請求できない。","ENG":"You don't know a thing about the loan shark business, do you? You won't get your money's worth if anything happens to the collateral.","TWN":"看來你對高利貸這一行完全不瞭解。如果抵押品受損，以後就不能拿回全額債款了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어쨌거나 사멸한 선진 문명의 유적이라니, 영화에서나 나올 법한 이야기군.","JPN":"ところで、滅びた先進文明の遺跡とは、映画に出てきそうな話だ。","ENG":"In any case, the ruins of a lost advanced civilization, sounds like something out of a sci-fi movie.","TWN":"不管怎樣，居然找到了已滅亡的先進文明遺跡，好像是電影裡才有的情節。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"안에 들어가서 평범하게 구경만 하진 않았을 것 같은데, 어땠나?","JPN":"中に入って普通に探査だけで終わったとは思えないが、どうだったかな？","ENG":"I suspect it wasn't exactly an ordinary sightseeing trip in there. How was it?","TWN":"進去之後應該不會只是簡單參觀吧，後面如何了？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그리 유쾌한 경험은 아니었어.","JPN":"そんなに愉快な経験ではなかった。","ENG":"It was anything but pleasant.","TWN":"那並不是一段很愉快的經歷。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"사고가 터졌거든.","JPN":"事故が起きたからな。","ENG":"Something went terribly wrong.","TWN":"意外發生了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};